questions.prompt:
In a bash voting module, the winning recommendation is produced by one function and the final 1-10 score by another. Name the most serious defect and why.

_map_sanitize_key() { echo "$1" | tr -cd '[:alnum:]_'; }

calculate_weighted_recommendation() {
  # ... picks the most-supported approach, then emits it as the winner key:
  winner=$(_map_sanitize_key "$top_approach")
  echo "{\"recommended_approach\": \"$winner\"}"
}

calculate_final_score() {
  local dir="$1" winner="$2" weighted_sum=0 total=0
  for f in "$dir"/*.json; do
    approach=$(jq -r '.response.approach' "$f")   # ORIGINAL string, e.g. "Use JWT with sessions"
    conf=$(jq -r '.confidence.score' "$f")
    total=$((total + conf))
    if [[ "$approach" == "$winner" ]]; then weighted_sum=$((weighted_sum + conf*10));
    else weighted_sum=$((weighted_sum + conf*2)); fi
  done
  echo $(( weighted_sum / total ))
}

This helper is called both as estimate_tokens "$text" and as `echo ... | estimate_tokens`. A test calls estimate_tokens "". Name the most serious defect and why.

estimate_tokens() {
  local text="${1:-}"
  if [[ -z "$text" ]]; then
    text=$(cat)   # read from stdin if no argument
  fi
  local chars
  chars=$(echo -n "$text" | wc -c | tr -d ' ')
  echo $((chars / 4))
}

Config declares per-agent wire-format overrides (QWEN3_FORMAT, GLM_FORMAT, ...) and .env.example documents them. The function that resolves the format is below. Name the most serious defect and why.

get_api_format() {
  local agent_upper; agent_upper=$(to_upper "$1")
  case "$agent_upper" in
    GEMINI) echo google_ai ;;
    CLAUDE) echo anthropic ;;
    QWEN3)  echo qwen ;;
    *)      echo openai ;;
  esac
}

This is the only writer of per-response metadata. Session cost is computed as sum over responses of tokens_used * model_rate. Users report every session costs about the same small amount regardless of the work done. Name the most serious defect and why.

build_response_metadata() {
  local latency="$1" model="$2"
  jq -n --argjson latency "$latency" --arg model "$model" \
    '{tokens_used: 0, latency_ms: $latency, model_version: $model}'
}

This test passes locally and in most CI runs but occasionally fails for one contributor. log_warn writes at WARN level and is suppressed when LOG_LEVEL=ERROR. Name the most serious defect and why.

test_bad_value_warns() {
  local out
  out=$(SOME_VAR=bogus get_api_format QWEN3 2>&1 >/dev/null)
  assert_match "not a known format" "$out" "bad value warns"
}

select_consultants ranks the roster by affinity and returns the top N. The caller uses its output directly when smart routing is on; the ENABLE_* and self-exclusion checks live only in the other (non-smart) code branch. Name the most serious defect and why.

select_consultants() {
  local category="$1" min="$2" max="$3" count=0
  for c in Gemini Codex Mistral Cursor Kimi Claude Qwen3 GLM Grok DeepSeek MiniMax; do
    [[ $(get_affinity "$category" "$c") -ge $min ]] || continue
    echo "$c"; count=$((count+1))
    [[ $count -ge $max ]] && break
  done
}
